(1, 4, 'Frontend', '{\"id\": \"static_frontend\", \"goal_title\": \"Frontend\", \"description\": \"Master modern frontend development from HTML to advanced JavaScript frameworks.\", \"difficulty\": \"Beginner\", \"hours_per_week\": 10, \"is_static\": true, \"modules\": [{\"id\": \"m0\", \"title\": \"Internet Basics\", \"order\": 0, \"topics\": [{\"id\": \"static_frontend_how_the_internet_works\", \"title\": \"How the Internet Works\", \"description\": \"Learn How the Internet Works as part of Internet Basics.\", \"key_concepts\": \"\", \"duration\": \"\", \"resources\": [], \"order\": 0, \"is_done\": false}, {\"id\": \"static_frontend_http_&_https\", \"title\": \"HTTP & HTTPS\", \"description\": \"Learn HTTP & HTTPS as part of Internet Basics.\", \"key_concepts\": \"\", \"duration\": \"\", \"resources\": [], \"order\": 1, \"is_done\": false}, {\"id\": \"static_frontend_dns_&_domain_names\", \"title\": \"DNS & Domain Names\", \"description\": \"Learn DNS & Domain Names as part of Internet Basics.\", \"key_concepts\": \"\", \"duration\": \"\", \"resources\": [], \"order\": 2, \"is_done\": false}, {\"id\": \"static_frontend_browsers_&_how_they_work\", \"title\": \"Browsers & How They Work\", \"description\": \"Learn Browsers & How They Work as part of Internet Basics.\", \"key_concepts\": \"\", \"duration\": \"\", \"resources\": [], \"order\": 3, \"is_done\": false}, {\"id\": \"static_frontend_hosting_&_cdns\", \"title\": \"Hosting & CDNs\", \"description\": \"Learn Hosting & CDNs as part of Internet Basics.\", \"key_concepts\": \"\", \"duration\": \"\", \"resources\": [], \"order\": 4, \"is_done\": false}, {\"id\": \"static_frontend_web_performance_basics\", \"title\": \"Web Performance Basics\", \"description\": \"Learn Web Performance Basics as part of Internet Basics.\", \"key_concepts\": \"\", \"duration\": \"\", \"resources\": [], \"order\": 5, \"is_done\": false}]}, {\"id\": \"m1\", \"title\": \"HTML Fundamentals\", \"order\": 1, \"topics\": [{\"id\": \"static_f