(3, 4, 'frontend developer Roadmap', '{\"goal_title\": \"frontend developer Roadmap\", \"description\": \"Become a proficient frontend developer with a strong foundation in modern web development technologies and practices\", \"modules\": [{\"title\": \"Fundamentals of Web Development\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"HTML5\", \"duration\": \"2h\", \"description\": \"Learn the basics of HTML5 structure and syntax\", \"key_concepts\": \"tags, attributes, semantic meaning\"}, {\"title\": \"CSS3\", \"duration\": \"2h\", \"description\": \"Understand the fundamentals of CSS3 selectors, properties, and values\", \"key_concepts\": \"selectors, properties, values, box model\"}, {\"title\": \"JavaScript Basics\", \"duration\": \"3 days\", \"description\": \"Learn the basics of JavaScript syntax, data types, and control structures\", \"key_concepts\": \"variables, data types, functions, control structures\"}, {\"title\": \"DOM Manipulation\", \"duration\": \"1 day\", \"description\": \"Understand how to interact with the Document Object Model\", \"key_concepts\": \"DOM, elements, attributes, events\"}, {\"title\": \"CSS Preprocessors\", \"duration\": \"1 day\", \"description\": \"Learn how to use CSS preprocessors like Sass or Less\", \"key_concepts\": \"variables, mixins, nesting\"}]}, {\"title\": \"Core Tools and Technologies\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Node.js and npm\", \"duration\": \"1 day\", \"description\": \"Understand the basics of Node.js and npm package management\", \"key_concepts\": \"Node.js, npm, packages, dependencies\"}, {\"title\": \"Git and Version Control\", \"duration\": \"1 day\", \"description\": \"Learn how to use Git for version control and collaboration\", \"key_concepts\": \"Git, repositories, commits, branches\"}, {\"title\": \"Webpack and Bundling\", \"duration\": \"2h\", \"description\": \"Understand how to use Webpack for bundling and optimization\", \"key_concepts\": \"Webpack, bundling, optimization, plugins\"}, {\"title\": \"Vite and Development Servers\", \"duration\": \"1 day\", \"description\": \"Learn how to use Vite for fast and efficient development\", \"key_concepts\": \"Vite, development servers, hot reloading\"}]}, {\"title\": \"Frontend Frameworks\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"React Basics\", \"duration\": \"3 days\", \"description\": \"Learn the fundamentals of React and its ecosystem\", \"key_concepts\": \"components, JSX, state, props\"}, {\"title\": \"React Hooks\", \"duration\": \"1 day\", \"description\": \"Understand how to use React Hooks for state and side effects\", \"key_concepts\": \"Hooks, useState, useEffect, useContext\"}, {\"title\": \"Angular and Vue.js\", \"duration\": \"2h\", \"description\": \"Get an introduction to Angular and Vue.js frameworks\", \"key_concepts\": \"Angular, Vue.js, components, templates\"}]}, {\"title\": \"Advanced Frontend Topics\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"State Management\", \"duration\": \"1 day\", \"description\": \"Learn how to manage state in complex frontend applications\", \"key_concepts\": \"state, reducers, actions, stores\"}, {\"title\": \"Server-Side Rendering\", \"duration\": \"1 day\", \"description\": \"Understand how to use server-side rendering for SEO and performance\", \"key_concepts\": \"SSR, Next.js, Gatsby\"}, {\"title\": \"Web Performance Optimization\", \"duration\": \"2h\", \"description\": \"Learn how to optimize frontend performance for better user experience\", \"key_concepts\": \"performance, optimization, caching, minification\"}]}, {\"title\": \"Testing and Debugging\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Jest and Unit Testing\", \"duration\": \"1 day\", \"description\": \"Learn how to write unit tests with Jest and React Testing Library\", \"key_concepts\": \"Jest, unit testing, mocking, assertions\"}, {\"title\": \"Cypress and End-to-End Testing\", \"duration\": \"1 day\", \"description\": \"Understand how to use Cypress for end-to-end testing and integration\", \"key_concepts\": \"Cypress, end-to-end testing, integration testing\"}, {\"title\": \"Playwright and Browser Automation\", \"duration\": \"2h\", \"description\": \"Learn how to use Playwright for browser automation and testing\", \"key_concepts\": \"Playwright, browser automation, testing\"}]}, {\"title\": \"Data Structures and Algorithms\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"Arrays and Linked Lists\", \"duration\": \"1 day\", \"description\": \"Learn the basics of arrays and linked lists data structures\", \"key_concepts\": \"arrays, linked lists, indexing, traversal\"}, {\"title\": \"Stacks and Queues\", \"duration\": \"1 day\", \"description\": \"Understand how to use stacks and queues for efficient data processing\", \"key_concepts\": \"stacks, queues, LIFO, FIFO\"}, {\"title\": \"Trees and Graphs\", \"duration\": \"2h\", \"description\": \"Learn the basics of trees and graphs data structures\", \"key_concepts\": \"trees, graphs, traversal, searching\"}]}, {\"title\": \"System Design and Architecture\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"System Design Principles\", \"duration\": \"1 day\", \"description\": \"Learn the fundamentals of system design and architecture\", \"key_concepts\": \"system design, architecture, scalability, reliability\"}, {\"title\": \"Microservices and Service-Oriented Architecture\", \"duration\": \"1 day\", \"description\": \"Understand how to design and implement microservices and SOA\", \"key_concepts\": \"microservices, SOA, services, communication\"}, {\"title\": \"Cloud Computing and Deployment\", \"duration\": \"2h\", \"description\": \"Learn how to deploy and manage applications in the cloud\", \"key_concepts\": \"cloud computing, deployment, scaling, monitoring\"}]}, {\"title\": \"Databases and Storage\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"Relational Databases\", \"duration\": \"1 day\", \"description\": \"Learn the basics of relational databases and SQL\", \"key_concepts\": \"relational databases, SQL, queries, schema\"}, {\"title\": \"NoSQL Databases\", \"duration\": \"1 day\", \"description\": \"Understand how to use NoSQL databases for flexible data storage\", \"key_concepts\": \"NoSQL databases, key-value stores, document databases\"}, {\"title\": \"Database Modeling and Design\", \"duration\": \"2h\", \"description\": \"Learn how to design and model databases for efficient data storage\", \"key_concepts\": \"database modeling, design, normalization, denormalization\"}]}, {\"title\": \"Security and Authentication\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Web Security Fundamentals\", \"duration\": \"1 day\", \"description\": \"Learn the basics of web security and common vulnerabilities\", \"key_concepts\": \"web security, vulnerabilities, threats, mitigation\"}, {\"title\": \"Authentication and Authorization\", \"duration\": \"1 day\", \"description\": \"Understand how to implement authentication and authorization in web applications\", \"key_concepts\": \"authentication, authorization, JWT, OAuth\"}, {\"title\": \"HTTPS and TLS\", \"duration\": \"2h\", \"description\": \"Learn how to use HTTPS and TLS for secure communication\", \"key_concepts\": \"HTTPS, TLS, certificates, encryption\"}]}, {\"title\": \"Production and Deployment\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Containerization with Docker\", \"duration\": \"1 day\", \"description\": \"Learn how to use Docker for containerization and deployment\", \"key_concepts\": \"Docker, containers, images, volumes\"}, {\"title\": \"Kubernetes and Orchestration\", \"duration\": \"1 day\", \"description\": \"Understand how to use Kubernetes for container orchestration and management\", \"key_concepts\": \"Kubernetes, orchestration, deployment, scaling\"}, {\"title\": \"CI/CD Pipelines and Automation\", \"duration\": \"2h\", \"description\": \"Learn how to automate deployment and testing with CI/CD pipelines\", \"key_concepts\": \"CI/CD, pipelines, automation, testing\"}]}], \"source\": \"AI Generated\"}', '2026-03-24 09:23:05'),
(4, 4, 'advanced atomic automation Roadmap', '{\"goal_title\": \"advanced atomic automation Roadmap\", \"description\": \"Master advanced atomic automation skills with a focus on industry tools and computer science fundamentals\", \"modules\": [{\"title\": \"Introduction to Automation\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Automation Basics\", \"duration\": \"2h\", \"description\": \"Understand the basics of automation and its applications\", \"key_concepts\": \"automation, scripting, workflow\"}, {\"title\": \"Python for Automation\", \"duration\": \"1 day\", \"description\": \"Learn Python basics for automation tasks\", \"key_concepts\": \"Python, variables, data types, control structures\"}, {\"title\": \"Automating Tasks with Python\", \"duration\": \"1 day\", \"description\": \"Use Python to automate simple tasks\", \"key_concepts\": \"Python, automation, scripting\"}, {\"title\": \"Introduction to Docker\", \"duration\": \"2h\", \"description\": \"Learn the basics of Docker and containerization\", \"key_concepts\": \"Docker, containerization, virtualization\"}, {\"title\": \"Dockerizing Applications\", \"duration\": \"1 day\", \"description\": \"Learn to dockerize applications and services\", \"key_concepts\": \"Docker, containerization, deployment\"}, {\"title\": \"Automation with Docker\", \"duration\": \"1 day\", \"description\": \"Use Docker to automate tasks and workflows\", \"key_concepts\": \"Docker, automation, workflow\"}, {\"title\": \"Data Structures for Automation\", \"duration\": \"2h\", \"description\": \"Learn basic data structures for automation tasks\", \"key_concepts\": \"data structures, arrays, lists, dictionaries\"}, {\"title\": \"Algorithms for Automation\", \"duration\": \"2h\", \"description\": \"Learn basic algorithms for automation tasks\", \"key_concepts\": \"algorithms, sorting, searching, graph traversal\"}]}, {\"title\": \"Core Automation Tools\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Play