(5, 4, 'devops Roadmap', '{\"goal_title\": \"devops Roadmap\", \"description\": \"A comprehensive learning journey to master devops skills for a career in the tech industry\", \"modules\": [{\"title\": \"Introduction to Devops\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Agile Methodologies\", \"duration\": \"2h\", \"description\": \"Understand the basics of agile development and its importance in devops\", \"key_concepts\": \"scrum,kanban,lean\"}]}, {\"title\": \"Version Control Systems\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Git Fundamentals\", \"duration\": \"1 day\", \"description\": \"Learn the basics of git and how to use it for version control\", \"key_concepts\": \"git,github,gitlab\"}, {\"title\": \"Git Branching and Merging\", \"duration\": \"2h\", \"description\": \"Understand how to use branching and merging in git\", \"key_concepts\": \"git,branching,merging\"}, {\"title\": \"Git Tools and Integrations\", \"duration\": \"1 day\", \"description\": \"Explore various git tools and integrations\", \"key_concepts\": \"git,gitkraken,gitextensions\"}]}, {\"title\": \"Containerization and Orchestration\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Docker Fundamentals\", \"duration\": \"2h\", \"description\": \"Learn the basics of docker and containerization\", \"key_concepts\": \"docker,containers,images\"}, {\"title\": \"Docker Compose and Networking\", \"duration\": \"1 day\", \"description\": \"Understand how to use docker compose and networking\", \"key_concepts\": \"docker,compose,networking\"}, {\"title\": \"Kubernetes Introduction\", \"duration\": \"2h\", \"description\": \"Get introduced to kubernetes and its importance in devops\", \"key_concepts\": \"kubernetes,orchestration,clusters\"}]}, {\"title\": \"Infrastructure as Code\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Terraform Introduction\", \"duration\": \"2h\", \"description\": \"Learn the basics of terraform and infrastructure 