\": \"3h\", \"description\": \"ARIA roles, screen readers.\", \"key_concepts\": \"WCAG,ARIA,alt text,contrast\"}, {\"title\": \"SEO Basics\", \"duration\": \"2h\", \"description\": \"Meta tags, structured data.\", \"key_concepts\": \"meta,og,ld+json,canonical\"}]}, {\"title\": \"CSS\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Learn the basics\", \"duration\": \"4h\", \"description\": \"Selectors, cascade, specificity.\", \"key_concepts\": \"selector,box model,specificity\"}, {\"title\": \"Making Layouts\", \"duration\": \"5h\", \"description\": \"Flexbox, Grid fundamentals.\", \"key_concepts\": \"flex,grid,float,position\"}, {\"title\": \"Responsive Design\", \"duration\": \"4h\", \"description\": \"Media queries, mobile-first.\", \"key_concepts\": \"media query,rem,vw,breakpoint\"}, {\"title\": \"Animations\", \"duration\": \"3h\", \"description\": \"Transitions and keyframes.\", \"key_concepts\": \"transition,@keyframes,transform\"}, {\"title\": \"CSS Variables\", \"duration\": \"2h\", \"description\": \"Custom properties.\", \"key_concepts\": \"var(),custom property,:root\"}, {\"title\": \"Pseudo classes & elements\", \"duration\": \"2h\", \"description\": \"::before, :hover, :nth-child.\", \"key_concepts\": \"::before,::after,:hover,:focus\"}]}, {\"title\": \"JavaScript\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Syntax & Basic Constructs\", \"duration\": \"5h\", \"description\": \"Variables, loops, functions.\", \"key_concepts\": \"let,const,function,loops\"}, {\"title\": \"DOM Manipulation\", \"duration\": \"4h\", \"description\": \"querySelector, events.\", \"key_concepts\": \"querySelector,addEventListener,DOM\"}, {\"title\": \"Fetch API / Ajax\", \"duration\": \"3h\", \"description\": \"Async requests, JSON.\", \"key_concepts\": \"fetch,async/await,JSON\"}, {\"title\": \"ES6+ Features\", \"duration\": \"4h\", \"description\": \"Arrow functions, destructuring.\", \"key_concepts\": \"arrow fn,destructuring,spread\"}, {\"title\": \"Promises & Async/Await\", \"duration\": \"3h\", \"description\": \"Asynchronous JavaScript.\", \"key_concepts\": \"Promise,async,await,.then\"}, {\"title\": \"Closures & Scope\", \"duration\": \"3h\", \"description\": \"Lexical scope, closures.\", \"key_concepts\": \"closure,scope,hoisting,IIFE\"}, {\"title\": \"Error Handling\", \"duration\": \"2h\", \"description\": \"try/catch, custom errors.\", \"key_concepts\": \"try,catch,Error,throw\"}, {\"title\": \"Modules\", \"duration\": \"2h\", \"description\": \"import/export, bundlers.\", \"key_concepts\": \"import,export,ESM,CJS\"}]}, {\"title\": \"Version Control Systems\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Git \\u2013 the basics\", \"duration\": \"3h\", \"description\": \"init, commit, log.\", \"key_concepts\": \"init,add,commit,log\"}, {\"title\": \"Branching & Merging\", \"duration\": \"3h\", \"description\": \"branches, merge, rebase.\", \"key_concepts\": \"branch,merge,rebase,conflict\"}, {\"title\": \"GitHub / GitLab\", \"duration\": \"2h\", \"description\": \"Remote repos, PRs.\", \"key_concepts\": \"push,pull,PR,fork\"}, {\"title\": \"Git Workflows\", \"duration\": \"2h\", \"description\": \"Gitflow, trunk-based.\", \"key_concepts\": \"gitflow,trunk,feature branch\"}]}, {\"title\": \"Package Managers\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"npm\", \"duration\": \"2h\", \"description\": \"Install, scripts, lock file.\", \"key_concepts\": \"install,publish,scripts,lock\"}, {\"title\": \"yarn\", \"duration\": \"1h\", \"description\": \"Workspaces, zero-install.\", \"key_concepts\": \"yarn add,workspaces,pnp\"}, {\"title\": \"pnpm\", \"duration\": \"1h\", \"description\": \"Disk-efficient package manager.\", \"key_concepts\": \"pnpm add,store,monorepo\"}]}, {\"title\": \"Pick a Framework\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"React\", \"duration\": \"2 weeks\", \"description\": \"Components, hooks, JSX.\", \"key_concepts\": \"hooks,JSX,state,props\"}, {\"title\": \"Vue.js\", \"duration\": \"2 weeks\", \"description\": \"Options/Composition API.\", \"key_concepts\": \"v-bind,v-model,computed\"}, {\"title\": \"Angular\", \"duration\": \"3 weeks\", \"description\": \"Full framework, TypeScript.\", \"key_concepts\": \"modules,DI,services,RxJS\"}, {\"title\": \"Svelte\", \"duration\": \"1 week\", \"description\": \"Compiled, no virtual DOM.\", \"key_concepts\": \"stores,reactive,$:\"}, {\"title\": \"Solid.js\", \"duration\": \"1 week\", \"description\": \"Fine-grained reactivity.\", \"key_concepts\": \"signals,effects,JSX\"}]}, {\"title\": \"CSS Architecture\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"BEM\", \"duration\": \"2h\", \"description\": \"Block Element Modifier naming.\", \"key_concepts\": \"block,element,modifier,naming\"}, {\"title\": \"Tailwind CSS\", \"duration\": \"4h\", \"description\": \"Utility-first CSS.\", \"key_concepts\": \"utility,purge,JIT,config\"}, {\"title\": \"CSS Modules\", \"duration\": \"2h\", \"description\": \"Scoped CSS per component.\", \"key_concepts\": \"module,composes,scoped\"}, {\"title\": \"Sass / SCSS\", \"duration\": \"3h\", \"description\": \"Variables, mixins, nesting.\", \"key_concepts\": \"$var,@mixin,@extend,nesting\"}, {\"title\": \"PostCSS\", \"duration\": \"1h\", \"description\": \"Transform CSS with plugins.\", \"key_concepts\": \"autoprefixer,cssnano,plugin\"}]}, {\"title\": \"Build Tools\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Vite\", \"duration\": \"3h\", \"description\": \"Fast dev server, HMR.\", \"key_concepts\": \"HMR,ESBuild,plugin,config\"}, {\"title\": \"Webpack\", \"duration\": \"4h\", \"description\": \"Module bundler, loaders.\", \"key_concepts\": \"loader,plugin,chunk,tree-shake\"}, {\"title\": \"Rollup\", \"duration\": \"2h\", \"description\": \"ES module bundler.\", \"key_concepts\": \"esm,treeshake,output,plugin\"}, {\"title\": \"esbuild\", \"duration\": \"1h\", \"description\": \"Extremely fast JS bundler.\", \"key_concepts\": \"bundle,minify,transform\"}, {\"title\": \"Linters & Formatters\", \"duration\": \"2h\", \"description\": \"ESLint, Prettier.\", \"key_concepts\": \"ESLint,Prettier,.eslintrc\"}, {\"title\": \"Docker basics\", \"duration\": \"3h\", \"description\": \"Containerise your app.\", \"key_concepts\": \"Dockerfile,image,container,compose\"}]}, {\"title\": \"Testing\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Unit Testing (Vitest/Jest)\", \"duration\": \"4h\", \"description\": \"Write fast, isolated tests.\", \"key_concepts\": \"describe,it,expect,mock\"}, {\"title\": \"Integration Testing\", \"duration\": \"3h\", \"description\": \"Test components together.\", \"key_concepts\": \"Testing Library,render,fireEvent\"}, {\"title\": \"E2E Testing (Playwright)\", \"duration\": \"4h\", \"description\": \"Browser automation tests.\", \"key_concepts\": \"page,locator,expect,CI\"}, {\"title\": \"Cypress\", \"duration\": \"3h\", \"description\": \"Component & E2E tests.\", \"key_concepts\": \"cy.get,cy.visit,fixture\"}]}, {\"title\": \"Web Security Basics\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"HTTPS & SSL/TLS\", \"duration\": \"2h\", \"description\": \"Certificates, handshake.\", \"key_concepts\": \"TLS,cert,HSTS,mixed content\"}, {\"title\": \"CORS\", \"duration\": \"2h\", \"description\": \"Cross-origin resource sharing.\", \"key_concepts\": \"origin,preflight,headers,credentials\"}, {\"title\": \"Content Security Policy\", \"duration\": \"2h\", \"description\": \"Restrict resource loading.\", \"key_concepts\": \"CSP,nonce,script-src,report\"}, {\"title\": \"OWASP Top 10\", \"duration\": \"3h\", \"description\": \"XSS, CSRF, injection.\", \"key_concepts\": \"XSS,CSRF,SQLi,A01-A10\"}, {\"title\": \"Authentication Strategies\", \"duration\": \"3h\", \"description\": \"JWT, OAuth, session auth.\", \"key_concepts\": \"JWT,OAuth,session,cookie\"}]}], \"source\": \"AI Generated\", \"is_saved\": true}', '2026-03-29 18:05:24'