(32, 4, 'quantam computing Roadmap', '{\"goal_title\": \"quantam computing Roadmap\", \"description\": \"A 12-hour-per-week learning journey to master intermediate-level quantam computing skills\", \"modules\": [{\"title\": \"Introduction to Quantam Computing\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Quantum Bits and Qubits\", \"duration\": \"2h\", \"description\": \"Understand the fundamental concepts of quantum bits and qubits\", \"key_concepts\": \"superposition,entanglement,quantum gates\", \"id\": \"32_quantum_bits_and_qubits\"}, {\"title\": \"Quantum Computing History\", \"duration\": \"1 day\", \"description\": \"Learn about the history and development of quantum computing\", \"key_concepts\": \"quantum mechanics,computer science,physics\", \"id\": \"32_quantum_computing_history\"}, {\"title\": \"Quantum Computing Applications\", \"duration\": \"2h\", \"description\": \"Explore the current and potential applications of quantum computing\", \"key_concepts\": \"cryptography,optimization,simulation\", \"id\": \"32_quantum_computing_applications\"}, {\"title\": \"Quantum Computing Hardware\", \"duration\": \"1 day\", \"description\": \"Understand the different types of quantum computing hardware\", \"key_concepts\": \"superconducting qubits,ion traps,topological quantum computers\", \"id\": \"32_quantum_computing_hardware\"}, {\"title\": \"Quantum Computing Software\", \"duration\": \"2h\", \"description\": \"Learn about the software frameworks used in quantum computing\", \"key_concepts\": \"Qiskit,Cirq,QuTiP\", \"id\": \"32_quantum_computing_software\"}]}, {\"title\": \"Quantum Computing Fundamentals\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Quantum Mechanics Basics\", \"duration\": \"3 days\", \"description\": \"Understand the principles of quantum mechanics\", \"key_concepts\": \"wave-particle duality,uncertainty principle,Schrodinger equation\", \"id\": \"32_quantum_mechanics_basics\"}, {\"title\": \"Quantum Information 