(35, 4, 'dasads Roadmap', '{\"goal_title\": \"dasads Roadmap\", \"description\": \"A beginner-friendly learning path for dasads, covering fundamentals to production-ready skills.\", \"modules\": [{\"title\": \"Introduction to Programming\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Variables and Data Types\", \"duration\": \"2h\", \"description\": \"Learn the basics of variables and data types in programming.\", \"key_concepts\": \"variables, data types, operators\", \"id\": \"35_variables_and_data_types\"}, {\"title\": \"Control Structures\", \"duration\": \"2h\", \"description\": \"Understand control structures such as if-else statements and loops.\", \"key_concepts\": \"if-else, loops, conditional statements\", \"id\": \"35_control_structures\"}, {\"title\": \"Functions\", \"duration\": \"1 day\", \"description\": \"Learn about functions and how to use them in programming.\", \"key_concepts\": \"functions, function calls, parameters\", \"id\": \"35_functions\"}, {\"title\": \"Object-Oriented Programming\", \"duration\": \"1 day\", \"description\": \"Introduction to object-oriented programming concepts.\", \"key_concepts\": \"classes, objects, inheritance\", \"id\": \"35_object-oriented_programming\"}, {\"title\": \"Basic Algorithms\", \"duration\": \"2h\", \"description\": \"Learn basic algorithms such as sorting and searching.\", \"key_concepts\": \"algorithms, sorting, searching\", \"id\": \"35_basic_algorithms\"}, {\"title\": \"Introduction to Data Structures\", \"duration\": \"1 day\", \"description\": \"Learn about basic data structures such as arrays and linked lists.\", \"key_concepts\": \"data structures, arrays, linked lists\", \"id\": \"35_introduction_to_data_structures\"}, {\"title\": \"Debugging Techniques\", \"duration\": \"1 day\", \"description\": \"Learn how to debug code using various techniques.\", \"key_concepts\": \"debugging, error handling, logging\", \"id\": \"35_debugging_techniques\"}, {\"title\": \"Version Control with G