(36, 4, 'YOUTUBE Roadmap', '{\"goal_title\": \"YOUTUBE Roadmap\", \"description\": \"Learn the fundamentals of YouTube and video content creation for a career in online media\", \"modules\": [{\"title\": \"Introduction to YouTube\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"YouTube Basics\", \"duration\": \"2h\", \"description\": \"Understand the basics of YouTube and its features\", \"key_concepts\": \"YouTube account,channel,video upload\", \"id\": \"36_youtube_basics\"}]}, {\"title\": \"Content Creation Fundamentals\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Scriptwriting for Videos\", \"duration\": \"1 day\", \"description\": \"Learn the basics of scriptwriting for YouTube videos\", \"key_concepts\": \"script structure,storytelling,dialogue\", \"id\": \"36_scriptwriting_for_videos\"}]}, {\"title\": \"Video Production Essentials\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Video Editing with DaVinci Resolve\", \"duration\": \"3 days\", \"description\": \"Learn the basics of video editing using DaVinci Resolve\", \"key_concepts\": \"video editing,transitions,visual effects\", \"id\": \"36_video_editing_with_davinci_resolve\"}]}, {\"title\": \"Audio and Visual Effects\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Audio Editing with Audacity\", \"duration\": \"1 week\", \"description\": \"Learn the basics of audio editing using Audacity\", \"key_concepts\": \"audio editing,noise reduction,equalization\", \"id\": \"36_audio_editing_with_audacity\"}]}, {\"title\": \"YouTube SEO and Optimization\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Keyword Research with Google Trends\", \"duration\": \"2h\", \"description\": \"Learn how to conduct keyword research using Google Trends\", \"key_concepts\": \"keyword research,search volume,trends\", \"id\": \"36_keyword_research_with_google_trends\"}]}, {\"title\": \"Channel Growth and Engagement\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"Building a Community with YouTube Live\", \"duration\": \"1 day\", \"description\": \"Learn how to build a community using YouTube Live\", \"key_concepts\": \"live streaming,community building,audience engagement\", \"id\": \"36_building_a_community_with_youtube_live\"}]}, {\"title\": \"Monetization and Revenue Streams\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"YouTube Monetization Policies\", \"duration\": \"2h\", \"description\": \"Understand YouTube\'s monetization policies and requirements\", \"key_concepts\": \"monetization policies,ad revenue,merchandise\", \"id\": \"36_youtube_monetization_policies\"}]}, {\"title\": \"Advanced Video Production Techniques\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"Color Grading with Adobe Premiere Pro\", \"duration\": \"3 days\", \"description\": \"Learn advanced color grading techniques using Adobe Premiere Pro\", \"key_concepts\": \"color grading,luts,video editing\", \"id\": \"36_color_grading_with_adobe_premiere_pro\"}]}, {\"title\": \"Video Marketing and Promotion\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Social Media Marketing with Hootsuite\", \"duration\": \"1 week\", \"description\": \"Learn how to promote your YouTube channel using social media marketing\", \"key_concepts\": \"social media marketing,hootsuite,scheduling\", \"id\": \"36_social_media_marketing_with_hootsuite\"}]}, {\"title\": \"Analytics and Performance Tracking\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"YouTube Analytics with Google Analytics\", \"duration\": \"2h\", \"description\": \"Learn how to track your YouTube channel\'s performance using Google Analytics\", \"key_concepts\": \"youtube analytics,google analytics,performance tracking\", \"id\": \"36_youtube_analytics_with_google_analytics\"}]}, {\"title\": \"Career Development and Networking\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Building a Personal Brand as a YouTuber\", \"duration\": \"1 day\", \"description\": \"Learn how to build a personal brand as a YouTuber\", \"key_concepts\": \"personal branding,branding,marketing\", \"id\": \"36_building_a_personal_brand_as_a_youtuber\"}]}, {\"title\": \"Staying Up-to-Date with Industry Trends\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Following Industry Leaders and Blogs\", \"duration\": \"2h\", \"description\": \"Learn how to stay up-to-date with the latest industry trends and news\", \"key_concepts\": \"industry trends,blogs,podcasts\", \"id\": \"36_following_industry_leaders_and_blogs\"}]}, {\"title\": \"Advanced YouTube Features and Tools\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Using YouTube Studio for Channel Management\", \"duration\": \"1 week\", \"description\": \"Learn how to use YouTube Studio for channel management and optimization\", \"key_concepts\": \"youtube studio,channel management,optimization\", \"id\": \"36_using_youtube_studio_for_channel_management\"}]}, {\"title\": \"Collaboration and Community Building\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Collaborating with Other YouTubers\", \"duration\": \"2h\", \"description\": \"Learn how to collaborate with other YouTubers and build a community\", \"key_concepts\": \"collaboration,community building,partnerships\", \"id\": \"36_collaborating_with_other_youtubers\"}]}, {\"title\": \"Final Project and Portfolio Development\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Creating a YouTube Channel Portfolio\", \"duration\": \"1 week\", \"description\": \"Learn how to create a portfolio of your YouTube channel\'s best work\", \"key_concepts\": \"portfolio development,channel portfolio,showreel\", \"id\": \"36_creating_a_youtube_channel_portfolio\"}]}], \"source\": \"AI Generated\", \"is_saved\": true, \"id\": \"36\"}', '2026-03-31 10:26:55'),
(37, 4, 'DOT NET Roadmap', '{\"goal_title\": \"DOT NET Roadmap\", \"description\": \"A beginner-friendly learning path for DOT NET, covering fundamentals to production-ready skills in 1 hour per week.\", \"modules\": [{\"title\": \"Introduction to DOT NET\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"What is DOT NET\", \"duration\": \"2h\", \"description\": \"Understand the basics of DOT NET and its ecosystem.\", \"key_concepts\": \"DOT NET,frameworks,libraries\", \"id\": \"37_what_is_dot_net\"}, {\"title\": \"Setting up Visual Studio\", \"duration\": \"1 day\", \"description\": \"Install and configure Visual Studio for DOT NET development.\", \"key_concepts\": \"Visual Studio,IDE,setup\", \"id\": \"37_setting_up_visual_studio\"}, {\"title\": \"C# Basics\", \"duration\": \"3 days\", \"description\": \"Learn the fundamentals of C# programming language.\", \"key_concepts\": \"C#,variables,data types\", \"id\": \"37_c#_basics\"}, {\"title\": \"DOT NET Core Overview\", \"duration\": \"1 week\", \"description\": \"Understand the DOT NET Core framework and its features.\", \"key_concepts\": \"DOT NET Core,framework, cross-platform\", \"id\": \"37_dot_net_core_overview\"}]}, {\"title\": \"Core Tools and Frameworks\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"ASP.NET Core\", \"duration\": \"2h\", \"description\": \"Learn the basics of ASP.NET Core framework.\", \"key_concepts\": \"ASP.NET Core,web development,framework\", \"id\": \"37_asp.net_core\"}, {\"title\": \"Entity Framework Core\", \"duration\": \"1 day\", \"description\": \"Understand the Entity Framework Core ORM tool.\", \"key_concepts\": \"Entity Framework Core,ORM,database\", \"id\": \"37_entity_framework_core\"}, {\"title\": \"DOT NET CLI\", \"duration\": \"3 days\", \"description\": \"Learn to use the DOT NET CLI for project creation and management.\", \"key_concepts\": \"DOT NET CLI,command line,project management\", \"id\": \"37_dot_net_cli\"}, {\"title\": \"NuGet Packages\", \"duration\": \"1 week\", \"description\": \"Understand how to use NuGet packages in DOT NET projects.\", \"key_concepts\": \"NuGet packages,dependencies,libraries\", \"id\": \"37_nuget_packages\"}]}, {\"title\": \"Data Structures and Algorithms\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Arrays and Lists\", \"duration\": \"2h\", \"description\": \"Learn to work with arrays and lists in C#.\", \"key_concepts\": \"arrays,lists,data structures\", \"id\": \"37_arrays_and_lists\"}, {\"title\": \"Stacks and Queues\", \"duration\": \"1 day\", \"description\": \"Understand the implementation of stacks and queues in C#.\", \"key_concepts\": \"stacks,queues,data structures\", \"id\": \"37_stacks_and_queues\"}, {\"title\": \"Sorting Algorithms\", \"duration\": \"3 days\", \"description\": \"Learn the basics of sorting algorithms in C#.\", \"key_concepts\": \"sorting algorithms,bubble sort,selection sort\", \"id\": \"37_sorting_algorithms\"}, {\"title\": \"Searching Algorithms\", \"duration\": \"1 week\", \"description\": \"Understand the implementation of searching algorithms in C#.\", \"key_concepts\": \"searching algorithms,linear search,binary search\", \"id\": \"37_searching_algorithms\"}]}, {\"title\": \"Databases and Cloud\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Introduction to SQL\", \"duration\": \"2h\", \"description\": \"Learn the basics of SQL and database querying.\", \"key_concepts\": \"SQL,database,querying\", \"id\": \"37_introduction_to_sql\"}, {\"title\": \"Azure SQL Database\", \"duration\": \"1 day\", \"description\": \"Understand how to use Azure SQL Database with DOT NET.\", \"key_concepts\": \"Azure SQL Database,cloud database\", \"id\": \"37_azure_sql_database\"}, {\"title\": \"Azure Storage\", \"duration\": \"3 days\", \"description\": \"Learn to use Azure Storage with DOT NET.\", \"key_concepts\": \"Azure Storage,cloud storage\", \"id\": \"37_azure_storage\"}, {\"title\": \"Cloud Deployment\", \"duration\": \"1 week\", \"description\": \"Understand how to deploy DOT NET applications to the cloud.\", \"key_concepts\": \"cloud deployment,Azure,DevOps\", \"id\": \"37_cloud_deployment\"}]}, {\"title\": \"Advanced Topics\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Dependency Injection\", \"duration\": \"2h\", \"description\": \"Learn to use dependency injection in DOT NET applications.\", \"key_concepts\": \"dependency injection,DI,loose coupling\", \"id\": \"37_dependency_injection\"}, {\"title\": \"Middleware and Filters\", \"duration\": \"1 day\", \"description\": \"Understand how to use middleware and filters in ASP.NET Core.\", \"key_concepts\": \"middleware,filters,ASP.NET Core\", \"id\": \"37_middleware_and_filters\"}, {\"title\": \"Authentication and Authorization\", \"duration\": \"3 days\", \"description\": \"Learn to implement authentication and authorization in DOT NET applications.\", \"key_concepts\": \"authentication,authorization,security\", \"id\": \"37_authentication_and_authorization\"}, {\"title\": \"Performance Optimization\", \"duration\": \"1 week\", \"description\": \"Understand how to optimize the performance of DOT NET applications.\", \"key_concepts\": \"performance optimization,benchmarking,profiling\", \"id\": \"37_performance_optimization\"}]}, {\"title\": \"Production-Ready Skills\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"Docker and Containerization\", \"duration\": \"2h\", \"description\": \"Learn to use Docker with DOT NET applications.\", \"key_concepts\": \"Docker,containerization,DevOps\", \"id\": \"37_docker_and_containerization\"}, {\"title\": \"Kubernetes and Orchestration\", \"duration\": \"1 day\", \"description\": \"Understand how to use Kubernetes with DOT NET applications.\", \"key_concepts\": \"Kubernetes,orchestration,DevOps\", \"id\": \"37_kubernetes_and_orchestration\"}, {\"title\": \"Monitoring and Logging\", \"duration\": \"3 days\", \"description\": \"Learn to monitor and log DOT NET applications.\", \"key_concepts\": \"monitoring,logging,DevOps\", \"id\": \"37_monitoring_and_logging\"}, {\"title\": \"CI/CD Pipelines\", \"duration\": \"1 week\", \"description\": \"Understand how to implement CI/CD pipelines for DOT NET applications.\", \"key_concepts\": \"CI/CD pipelines,DevOps,automation\", \"id\": \"37_ci/cd_pipelines\"}]}, {\"title\": \"Career Development\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"Resume Building\", \"duration\": \"2h\", \"description\": \"Learn to build a resume for a DOT NET developer position.\", \"key_concepts\": \"resume building,career development\", \"id\": \"37_resume_building\"}, {\"title\": \"Interview Preparation\", \"duration\": \"1 day\", \"description\": \"Understand how to prepare for a DOT NET developer interview.\", \"key_concepts\": \"interview preparation,career development\", \"id\": \"37_interview_preparation\"}, {\"title\": \"Networking and Community\", \"duration\": \"3 days\", \"description\": \"Learn to network and participate in the DOT NET community.\", \"key_concepts\": \"networking,community,career development\", \"id\": \"37_networking_and_community\"}, {\"title\": \"Staying Up-to-Date\", \"duration\": \"1 week\", \"description\": \"Understand how to stay up-to-date with the latest DOT NET developments.\", \"key_concepts\": \"staying up-to-date,career development,industry trends\", \"id\": \"37_staying_up-to-date\"}]}, {\"title\": \"Final Project\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"Project Planning\", \"duration\": \"2h\", \"description\": \"Plan a final project to demonstrate DOT NET skills.\", \"key_concepts\": \"project planning,final project\", \"id\": \"37_project_planning\"}, {\"title\": \"Project Implementation\", \"duration\": \"1 week\", \"description\": \"Implement the final project using DOT NET skills.\", \"key_concepts\": \"project implementation,final project\", \"id\": \"37_project_implementation\"}, {\"title\": \"Project Deployment\", \"duration\": \"1 week\", \"description\": \"Deploy the final project to a production environment.\", \"key_concepts\": \"project deployment,final project\", \"id\": \"37_project_deployment\"}, {\"title\": \"Project Review\", \"duration\": \"1 week\", \"description\": \"Review and reflect on the final project experience.\", \"key_concepts\": \"project review,final project\", \"id\": \"37_project_review\"}]}, {\"title\": \"Additional Resources\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"DOT NET Documentation\", \"duration\": \"2h\", \"description\": \"Explore the official DOT NET documentation.\", \"key_concepts\": \"DOT NET documentation,official resources\", \"id\": \"37_dot_net_documentation\"}, {\"title\": \"Online Courses and Tutorials\", \"duration\": \"1 day\", \"description\": \"Find online courses and tutorials for DOT NET development.\", \"key_concepts\": \"online courses,tutorials,learning resources\", \"id\": \"37_online_courses_and_tutorials\"}, {\"title\": \"Books and eBooks\", \"duration\": \"3 days\", \"description\": \"Discover books and eBooks for DOT NET development.\", \"key_concepts\": \"books,eBooks,learning resources\", \"id\": \"37_books_and_ebooks\"}, {\"title\": \"Communities and Forums\", \"duration\": \"1 week\", \"description\": \"Participate in DOT NET communities and forums.\", \"key_concepts\": \"communities,forums,learning resources\", \"id\": \"37_communities_and_forums\"}]}, {\"title\": \"Conclusion\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Summary of Key Concepts\", \"duration\": \"2h\", \"description\": \"Review the key concepts learned throughout the roadmap.\", \"key_concepts\": \"key concepts,review,summary\", \"id\": \"37_summary_of_key_concepts\"}, {\"title\": \"Future Learning Paths\", \"duration\": \"1 day\", \"description\": \"Explore future learning paths for DOT NET development.\", \"key_concepts\": \"future learning paths,career development\", \"id\": \"37_future_learning_paths\"}, {\"title\": \"Final Thoughts and Recommendations\", \"duration\": \"3 days\", \"description\": \"Reflect on the learning experience and provide recommendations.\", \"key_concepts\": \"final thoughts,recommendations,learning experience\", \"id\": \"37_final_thoughts_and_recommendations\"}]}], \"source\": \"AI Generated\", \"is_saved\": true, \"id\": \"37\"}', '2026-03-31 10:28:07'),
(38, 14, 'dot net Roadmap', '{\"goal_title\": \"dot net Roadmap\", \"description\": \"A beginner-friendly learning roadmap for dot net covering fundamentals, core tools, frameworks, and advanced topics\", \"modules\": [{\"title\": \"Introduction to dot net\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"What is dot net\", \"duration\": \"2h\", \"description\": \"Understand the basics of dot net and its ecosystem\", \"key_concepts\": \"dot net, .NET Framework, .NET Core\", \"id\": \"38_what_is_dot_net\"}, {\"title\": \"Setting up the development environment\", \"duration\": \"1 day\", \"description\": \"Install and configure the necessary tools for dot net development\", \"key_concepts\": \"Visual Studio, Visual Studio Code, .NET SDK\", \"id\": \"38_setting_up_the_development_environment\"}, {\"title\": \"Basic syntax and data types\", \"duration\": \"2h\", \"description\": \"Learn the basic syntax and data types in C#\", \"key_concepts\": \"C#, variables, data types\", \"id\": \"38_basic_syntax_and_data_types\"}, {\"title\": \"Control structures and functions\", \"duration\": \"2h\", \"description\": \"Understand control structures and functions in C#\", \"key_concepts\": \"if-else statements, loops, functions\", \"id\": \"38_control_structures_and_functions\"}, {\"title\": \"Object-Oriented Programming (OOP) concepts\", \"duration\": \"3 days\", \"description\": \"Learn the basics of OOP in C#\", \"key_concepts\": \"classes, objects, inheritance, polymorphism\", \"id\": \"38_object-oriented_programming_(oop)_concepts\"}, {\"title\": \"Introduction to ASP.NET Core\", \"duration\": \"1 week\", \"description\": \"Get started with building web applications using ASP.NET Core\", \"key_concepts\": \"ASP.NET Core, MVC, Razor Pages\", \"id\": \"38_introduction_to_asp.net_core\"}]}, {\"title\": \"Core Tools and Frameworks\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Entity Framework Core\", \"duration\": \"2h\", \"description\": \"Learn how to u