: \"38_project_planning_and_design\"}, {\"title\": \"Project implementation\", \"duration\": \"3 days\", \"description\": \"Implement a dot net project\", \"key_concepts\": \"project implementation, coding, testing\", \"id\": \"38_project_implementation\"}, {\"title\": \"Project deployment and maintenance\", \"duration\": \"1 day\", \"description\": \"Deploy and maintain a dot net project\", \"key_concepts\": \"project deployment, project maintenance, monitoring\", \"id\": \"38_project_deployment_and_maintenance\"}]}, {\"title\": \"Additional Resources\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"dot net community and forums\", \"duration\": \"2h\", \"description\": \"Explore the dot net community and forums for learning and support\", \"key_concepts\": \"dot net community, forums, learning resources\", \"id\": \"38_dot_net_community_and_forums\"}, {\"title\": \"dot net blogs and podcasts\", \"duration\": \"1 day\", \"description\": \"Discover dot net blogs and podcasts for staying up-to-date with industry trends\", \"key_concepts\": \"dot net blogs, podcasts, industry trends\", \"id\": \"38_dot_net_blogs_and_podcasts\"}, {\"title\": \"dot net books and courses\", \"duration\": \"1 day\", \"description\": \"Find dot net books and courses for further learning and professional development\", \"key_concepts\": \"dot net books, courses, learning resources\", \"id\": \"38_dot_net_books_and_courses\"}]}, {\"title\": \"Conclusion and Next Steps\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Review and reflection\", \"duration\": \"2h\", \"description\": \"Review and reflect on the learning journey\", \"key_concepts\": \"review, reflection, learning journey\", \"id\": \"38_review_and_reflection\"}, {\"title\": \"Setting goals and creating a plan\", \"duration\": \"1 day\", \"description\": \"Set goals and create a plan for continued learning and professional growth\", \"key_concepts\": \"goal setting, planning, professional growth\", \"id\": \"38_setting_goals_and_creating_a_plan\"}, {\"title\": \"Staying up-to-date with industry trends\", \"duration\": \"1 day\", \"description\": \"Learn how to stay up-to-date with industry trends and developments in the dot net ecosystem\", \"key_concepts\": \"industry trends, staying current, professional development\", \"id\": \"38_staying_up-to-date_with_industry_trends\"}]}, {\"title\": \"Final Assessment and Evaluation\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Self-assessment and evaluation\", \"duration\": \"2h\", \"description\": \"Assess and evaluate your learning and progress\", \"key_concepts\": \"self-assessment, evaluation, learning progress\", \"id\": \"38_self-assessment_and_evaluation\"}, {\"title\": \"Identifying areas for improvement\", \"duration\": \"1 day\", \"description\": \"Identify areas for improvement and create a plan for addressing them\", \"key_concepts\": \"areas for improvement, plan, learning strategy\", \"id\": \"38_identifying_areas_for_improvement\"}, {\"title\": \"Creating a portfolio and showcasing skills\", \"duration\": \"1 day\", \"description\": \"Create a portfolio and showcase your skills and projects\", \"key_concepts\": \"portfolio, showcasing skills, career development\", \"id\": \"38_creating_a_portfolio_and_showcasing_skills\"}]}], \"source\": \"AI Generated\", \"is_saved\": true, \"id\": \"38\"}', '2026-03-31 10:54:58'),
(41, 4, 'snow flake Roadmap', '{\"goal_title\": \"snow flake Roadmap\", \"description\": \"Learn the fundamentals of snowflake, a cloud-based data warehousing platform, and its applications in data engineering and analytics\", \"modules\": [{\"title\": \"Introduction to Snowflake\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Snowflake Basics\", \"duration\": \"2h\", \"description\": \"Understand the core concepts of Snowflake, including data warehousing and cloud computing\", \"key_concepts\": \"data warehousing, cloud computing, scalability\", \"id\": \"41_snowflake_basics\"}]}, {\"title\": \"Setting up Snowflake\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Creating a Snowflake Account\", \"duration\": \"1h\", \"description\": \"Learn how to create a Snowflake account and set up a new project\", \"key_concepts\": \"account creation, project setup, roles and permissions\", \"id\": \"41_creating_a_snowflake_account\"}]}, {\"title\": \"Snowflake Core Concepts\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Databases and Schemas\", \"duration\": \"2h\", \"description\": \"Understand how to create and manage databases and schemas in Snowflake\", \"key_concepts\": \"databases, schemas, tables, views\", \"id\": \"41_databases_and_schemas\"}]}, {\"title\": \"Data Loading and Unloading\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Loading Data from CSV\", \"duration\": \"2h\", \"description\": \"Learn how to load data from CSV files into Snowflake\", \"key_concepts\": \"data loading, CSV, file formats\", \"id\": \"41_loading_data_from_csv\"}]}, {\"title\": \"Data Transformation and Querying\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Using SQL in Snowflake\", \"duration\": \"3 days\", \"description\": \"Learn how to write SQL queries to transform and analyze data in Snowflake\", \"key_concepts\": \"SQL, querying, data transformation\", \"id\": \"41_using_sql_in_snowflake\"}]}, {\"title\": \"Data Modeling and Design\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"Data Modeling Best Practices\", \"duration\": \"1 week\", \"description\": \"Understand how to design and implement effective data models in Snowflake\", \"key_concepts\": \"data modeling, entity-relationship diagrams, data governance\", \"id\": \"41_data_modeling_best_practices\"}]}, {\"title\": \"Snowflake Security and Access Control\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"Role-Based Access Control\", \"duration\": \"2h\", \"description\": \"Learn how to implement role-based access control in Snowflake\", \"key_concepts\": \"access control, roles, permissions\", \"id\": \"41_role-based_access_control\"}]}, {\"title\": \"Data Warehousing and ETL\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"Introduction to ETL Tools\", \"duration\": \"2h\", \"description\": \"Understand how to use ETL tools to load and transform data in Snowflake\", \"key_concepts\": \"ETL, data integration, data pipelines\", \"id\": \"41_introduction_to_etl_tools\"}]}, {\"title\": \"Advanced Snowflake Topics\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Using Snowflake with Python\", \"duration\": \"3 days\", \"description\": \"Learn how to use Python to interact with Snowflake and perform data analysis\", \"key_concepts\": \"Python, Snowflake API, data science\", \"id\": \"41_using_snowflake_with_python\"}]}, {\"title\": \"Snowflake in Production\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Monitoring and Optimizing Snowflake Performance\", \"duration\": \"1 week\", \"description\": \"Understand how to monitor and optimize Snowflake performance in a production environment\", \"key_concepts\": \"performance monitoring, optimization, cost management\", \"id\": \"41_monitoring_and_optimizing_snowflake_performance\"}]}], \"source\": \"AI Generated\", \"is_saved\": true, \"id\": \"41\"}', '2026-03-31 15:23:14'),
(42, 4, 'python Roadmap', '{\"goal_title\": \"python Roadmap\", \"description\": \"Learn the fundamentals of Python programming and its applications in the industry with a focus on real-world tools and technologies.\", \"modules\": [{\"title\": \"Introduction to Python\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Python Basics\", \"duration\": \"2h\", \"description\": \"Learn the basic syntax and data types of Python\", \"key_concepts\": \"variables, data types, operators, control structures\", \"id\": \"42_python_basics\"}, {\"title\": \"Setting up Python Environment\", \"duration\": \"1h\", \"description\": \"Install Python and set up a development environment\", \"key_concepts\": \"IDEs, text editors, package managers\", \"id\": \"42_setting_up_python_environment\"}, {\"title\": \"Basic Data Structures\", \"duration\": \"2h\", \"description\": \"Learn about lists, tuples, and dictionaries in Python\", \"key_concepts\": \"lists, tuples, dictionaries, indexing, slicing\", \"id\": \"42_basic_data_structures\"}, {\"title\": \"Control Structures\", \"duration\": \"1h\", \"description\": \"Learn about if-else statements, for loops, and while loops in Python\", \"key_concepts\": \"if-else, for loops, while loops, conditional statements\", \"id\": \"42_control_structures\"}, {\"title\": \"Functions in Python\", \"duration\": \"1h\", \"description\": \"Learn about functions, function arguments, and return types in Python\", \"key_concepts\": \"functions, function arguments, return types, lambda functions\", \"id\": \"42_functions_in_python\"}, {\"title\": \"Modules and Packages\", \"duration\": \"1h\", \"description\": \"Learn about importing modules and packages in Python\", \"key_concepts\": \"modules, packages, imports, pip\", \"id\": \"42_modules_and_packages\"}, {\"title\": \"Basic Error Handling\", \"duration\": \"1h\", \"description\": \"Learn about try-except blocks and error handling in Python\", \"key_concepts\": \"try-except, error handling, exceptions\", \"id\": \"42_basic_error_handling\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using Python basics\", \"key_concepts\": \"problem-solving, coding challenges\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Core Python Concepts\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Object-Oriented Programming\", \"duration\": \"2h\", \"description\": \"Learn about classes, objects, and inheritance in Python\", \"key_concepts\": \"classes, objects, inheritance, polymorphism\", \"id\": \"42_object-oriented_programming\"}, {\"title\": \"File Input/Output\", \"duration\": \"1h\", \"description\": \"Learn about reading and writing files in Python\", \"key_concepts\": \"file I/O, reading files, writing files\", \"id\": \"42_file_input/output\"}, {\"title\": \"Regular Expressions\", \"duration\": \"1h\", \"description\": \"Learn about regular expressions and pattern matching in Python\", \"key_concepts\": \"regular expressions, pattern matching, string manipulation\", \"id\": \"42_regular_expressions\"}, {\"title\": \"Data Structures - Sets and Frozensets\", \"duration\": \"1h\", \"description\": \"Learn about sets and frozensets in Python\", \"key_concepts\": \"sets, frozensets, set operations\", \"id\": \"42_data_structures_-_sets_and_frozensets\"}, {\"title\": \"Data Structures - Lists and Tuples\", \"duration\": \"1h\", \"description\": \"Learn about advanced list and tuple operations in Python\", \"key_concepts\": \"list comprehension, tuple unpacking, slicing\", \"id\": \"42_data_structures_-_lists_and_tuples\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using core Python concepts\", \"key_concepts\": \"problem-solving, coding challenges\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Data Analysis with Python\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Introduction to Pandas\", \"duration\": \"2h\", \"description\": \"Learn about the Pandas library and data manipulation in Python\", \"key_concepts\": \"Pandas, data frames, series, data manipulation\", \"id\": \"42_introduction_to_pandas\"}, {\"title\": \"Data Visualization with Matplotlib\", \"duration\": \"1h\", \"description\": \"Learn about data visualization using Matplotlib in Python\", \"key_concepts\": \"Matplotlib, data visualization, plots, charts\", \"id\": \"42_data_visualization_with_matplotlib\"}, {\"title\": \"Data Analysis with NumPy\", \"duration\": \"1h\", \"description\": \"Learn about numerical computing using NumPy in Python\", \"key_concepts\": \"NumPy, numerical computing, arrays, vectorized operations\", \"id\": \"42_data_analysis_with_numpy\"}, {\"title\": \"Data Cleaning and Preprocessing\", \"duration\": \"1h\", \"description\": \"Learn about data cleaning and preprocessing techniques in Python\", \"key_concepts\": \"data cleaning, data preprocessing, handling missing values\", \"id\": \"42_data_cleaning_and_preprocessing\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using data analysis concepts\", \"key_concepts\": \"problem-solving, data analysis\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Web Development with Python\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Introduction to Flask\", \"duration\": \"2h\", \"description\": \"Learn about the Flask web framework and building web applications in Python\", \"key_concepts\": \"Flask, web development, routes, templates\", \"id\": \"42_introduction_to_flask\"}, {\"title\": \"Introduction to Django\", \"duration\": \"2h\", \"description\": \"Learn about the Django web framework and building web applications in Python\", \"key_concepts\": \"Django, web development, models, views\", \"id\": \"42_introduction_to_django\"}, {\"title\": \"Database Integration with SQLite\", \"duration\": \"1h\", \"description\": \"Learn about database integration using SQLite in Python\", \"key_concepts\": \"SQLite, database integration, CRUD operations\", \"id\": \"42_database_integration_with_sqlite\"}, {\"title\": \"API Development with Python\", \"duration\": \"1h\", \"description\": \"Learn about building RESTful APIs using Python\", \"key_concepts\": \"API development, RESTful APIs, API design\", \"id\": \"42_api_development_with_python\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using web development concepts\", \"key_concepts\": \"problem-solving, web development\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Advanced Python Topics\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Concurrency and Parallelism\", \"duration\": \"2h\", \"description\": \"Learn about concurrency and parallelism in Python\", \"key_concepts\": \"concurrency, parallelism, threads, processes\", \"id\": \"42_concurrency_and_parallelism\"}, {\"title\": \"Asyncio and Async/Await\", \"duration\": \"1h\", \"description\": \"Learn about asynchronous programming using Asyncio in Python\", \"key_concepts\": \"asyncio, async/await, asynchronous programming\", \"id\": \"42_asyncio_and_async/await\"}, {\"title\": \"Type Hinting and Static Analysis\", \"duration\": \"1h\", \"description\": \"Learn about type hinting and static analysis in Python\", \"key_concepts\": \"type hinting, static analysis, mypy\", \"id\": \"42_type_hinting_and_static_analysis\"}, {\"title\": \"Testing and Debugging\", \"duration\": \"1h\", \"description\": \"Learn about testing and debugging techniques in Python\", \"key_concepts\": \"testing, debugging, unittest, pytest\", \"id\": \"42_testing_and_debugging\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using advanced Python concepts\", \"key_concepts\": \"problem-solving, advanced Python\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Production and Career Development\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"Containerization with Docker\", \"duration\": \"2h\", \"description\": \"Learn about containerization using Docker in Python\", \"key_concepts\": \"Docker, containerization, Dockerfiles\", \"id\": \"42_containerization_with_docker\"}, {\"title\": \"Cloud Deployment with AWS\", \"duration\": \"2h\", \"description\": \"Learn about cloud deployment using AWS in Python\", \"key_concepts\": \"AWS, cloud deployment, EC2, S3\", \"id\": \"42_cloud_deployment_with_aws\"}, {\"title\": \"DevOps and CI/CD Pipelines\", \"duration\": \"1h\", \"description\": \"Learn about DevOps and CI/CD pipelines in Python\", \"key_concepts\": \"DevOps, CI/CD pipelines, Jenkins, GitLab CI\", \"id\": \"42_devops_and_ci/cd_pipelines\"}, {\"title\": \"Career Development and Networking\", \"duration\": \"1h\", \"description\": \"Learn about career development and networking in the Python community\", \"key_concepts\": \"career development, networking, Python community\", \"id\": \"42_career_development_and_networking\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using production and career development concepts\", \"key_concepts\": \"problem-solving, production, career development\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Data Science and Machine Learning\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"Introduction to Scikit-Learn\", \"duration\": \"2h\", \"description\": \"Learn about the Scikit-Learn library and machine learning in Python\", \"key_concepts\": \"Scikit-Learn, machine learning, classification, regression\", \"id\": \"42_introduction_to_scikit-learn\"}, {\"title\": \"Introduction to TensorFlow\", \"duration\": \"2h\", \"description\": \"Learn about the TensorFlow library and deep learning in Python\", \"key_concepts\": \"TensorFlow, deep learning, neural networks, convolutional neural networks\", \"id\": \"42_introduction_to_tensorflow\"}, {\"title\": \"Data Preprocessing and Feature Engineering\", \"duration\": \"1h\", \"description\": \"Learn about data preprocessing and feature engineering in Python\", \"key_concepts\": \"data preprocessing, feature engineering, data manipulation\", \"id\": \"42_data_preprocessing_and_feature_engineering\"}, {\"title\": \"Model Evaluation and Hyperparameter Tuning\", \"duration\": \"1h\", \"description\": \"Learn about model evaluation and hyperparameter tuning in Python\", \"key_concepts\": \"model evaluation, hyperparameter tuning, cross-validation\", \"id\": \"42_model_evaluation_and_hyperparameter_tuning\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using data science and machine learning concepts\", \"key_concepts\": \"problem-solving, data science, machine learning\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"System Design and Architecture\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"Introduction to System Design\", \"duration\": \"2h\", \"description\": \"Learn about system design principles and patterns in Python\", \"key_concepts\": \"system design, design patterns, scalability, availability\", \"id\": \"42_introduction_to_system_design\"}, {\"title\": \"Microservices Architecture\", \"duration\": \"1h\", \"description\": \"Learn about microservices architecture and its applications in Python\", \"key_concepts\": \"microservices, service-oriented architecture, containerization\", \"id\": \"42_microservices_architecture\"}, {\"title\": \"Database Design and Modeling\", \"duration\": \"1h\", \"description\": \"Learn about database design and modeling in Python\", \"key_concepts\": \"database design, data modeling, entity-relationship diagrams\", \"id\": \"42_database_design_and_modeling\"}, {\"title\": \"Cache and Content Delivery Networks\", \"duration\": \"1h\", \"description\": \"Learn about cache and content delivery networks in Python\", \"key_concepts\": \"cache, content delivery networks, CDNs, caching strategies\", \"id\": \"42_cache_and_content_delivery_networks\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using system design and architecture concepts\", \"key_concepts\": \"problem-solving, system design, architecture\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Cloud and DevOps\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Introduction to Cloud Computing\", \"duration\": \"2h\", \"description\": \"Learn about cloud computing and its applications in Python\", \"key_concepts\": \"cloud computing, cloud providers, cloud services\", \"id\": \"42_introduction_to_cloud_computing\"}, {\"title\": \"AWS and Azure Services\", \"duration\": \"1h\", \"description\": \"Learn about AWS and Azure services and their applications in Python\", \"key_concepts\": \"AWS, Azure, cloud services, cloud storage\", \"id\": \"42_aws_and_azure_services\"}, {\"title\": \"Kubernetes and Container Orchestration\", \"duration\": \"1h\", \"description\": \"Learn about Kubernetes and container orchestration in Python\", \"key_concepts\": \"Kubernetes, container orchestration, pods, deployments\", \"id\": \"42_kubernetes_and_container_orchestration\"}, {\"title\": \"CI/CD Pipelines and Automation\", \"duration\": \"1h\", \"description\": \"Learn about CI/CD pipelines and automation in Python\", \"key_concepts\": \"CI/CD pipelines, automation, Jenkins, GitLab CI\", \"id\": \"42_ci/cd_pipelines_and_automation\"}, {\"title\": \"Practice Problems\", \"duration\": \"2h\", \"description\": \"Practice solving problems using cloud and DevOps concepts\", \"key_concepts\": \"problem-solving, cloud, DevOps\", \"id\": \"42_practice_problems\"}]}, {\"title\": \"Final Project and Review\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Final Project\", \"duration\": \"1 week\", \"description\": \"Work on a final project that integrates all the concepts learned in the roadmap\", \"key_concepts\": \"final project, integration, problem-solving\", \"id\": \"42_final_project\"}, {\"title\": \"Review and Practice\", \"duration\": \"2h\", \"description\": \"Review and practice all the concepts learned in the roadmap\", \"key_concepts\": \"review, practice, problem-solving\", \"id\": \"42_review_and_practice\"}, {\"title\": \"Career Development and Networking\", \"duration\": \"1h\", \"description\": \"Learn about career development and networking in the Python community\", \"key_concepts\": \"career development, networking, Python community\", \"id\": \"42_career_development_and_networking\"}, {\"title\": \"Next Steps and Further Learning\", \"duration\": \"1h\", \"description\": \"Learn about next steps and further learning opportunities in Python\", \"key_concepts\": \"next steps, further learning, Python community\", \"id\": \"42_next_steps_and_further_learning\"}]}], \"source\": \"AI Generated\", \"is_saved\": true, \"id\": \"42\"}', '2026-03-31 15:25:23');
