(44, 4, 'Basic elelectrical and electronical engineering Roadmap', '{\"goal_title\": \"Basic elelectrical and electronical engineering Roadmap\", \"description\": \"A beginner\'s roadmap to learning the fundamentals of electrical and electronic engineering\", \"modules\": [{\"title\": \"Introduction to Electrical Engineering\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Ohm\'s Law\", \"duration\": \"2h\", \"description\": \"Understand the relationship between voltage, current, and resistance\", \"key_concepts\": \"voltage, current, resistance, power\", \"id\": \"44_ohm\'s_law\"}]}, {\"title\": \"Circuit Analysis\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Series and Parallel Circuits\", \"duration\": \"3 days\", \"description\": \"Learn to analyze and solve circuit problems\", \"key_concepts\": \"series circuits, parallel circuits, Kirchhoff\'s laws\", \"id\": \"44_series_and_parallel_circuits\"}]}, {\"title\": \"Electronic Components\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Resistors and Capacitors\", \"duration\": \"1 day\", \"description\": \"Understand the properties and applications of resistors and capacitors\", \"key_concepts\": \"resistance, capacitance, reactance\", \"id\": \"44_resistors_and_capacitors\"}]}, {\"title\": \"Microcontrollers and Programming\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Introduction to Arduino\", \"duration\": \"2h\", \"description\": \"Learn the basics of microcontroller programming with Arduino\", \"key_concepts\": \"Arduino IDE, C++ programming, digital inputs and outputs\", \"id\": \"44_introduction_to_arduino\"}]}, {\"title\": \"Digital Logic and Electronics\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"Boolean Algebra and Logic Gates\", \"duration\": \"1 week\", \"description\": \"Understand the fundamentals of digital logic and electronics\", \"key_concepts\": \"Boolean algebra, logic gates, flip-flops\", \"id\": \"44_boolean_algebra_and_logic_gates\"}]}, {\"title\": \"Electrical Power Systems\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"AC and DC Power Systems\", \"duration\": \"3 days\", \"description\": \"Learn about the principles of electrical power systems\", \"key_concepts\": \"AC power, DC power, transformers, transmission lines\", \"id\": \"44_ac_and_dc_power_systems\"}]}, {\"title\": \"Electromagnetism and Signals\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"Electromagnetic Induction\", \"duration\": \"2h\", \"description\": \"Understand the principles of electromagnetic induction\", \"key_concepts\": \"electromagnetic induction, Faraday\'s law, Lenz\'s law\", \"id\": \"44_electromagnetic_induction\"}]}, {\"title\": \"Communication Systems\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"Introduction to Communication Systems\", \"duration\": \"1 day\", \"description\": \"Learn the basics of communication systems\", \"key_concepts\": \"communication systems, modulation, demodulation, transmission\", \"id\": \"44_introduction_to_communication_systems\"}]}, {\"title\": \"Control Systems and Robotics\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Introduction to Control Systems\", \"duration\": \"2h\", \"description\": \"Understand the principles of control systems\", \"key_concepts\": \"control systems, feedback control, stability\", \"id\": \"44_introduction_to_control_systems\"}]}, {\"title\": \"Career Development and Industry Applications\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Industry Applications of Electrical Engineering\", \"duration\": \"1 week\", \"description\": \"Explore the various applications of electrical engineering in industry\", \"key_concepts\": \"renewable energy, power systems, electronics, robotics\", \"id\": \"44_industry_applications_of_electrical_engineering\"}]}], \"source\": \"AI Generated\", \"is_saved\": true, \"id\": \"44\"}', '2026-04-01 14:40:26');
INSERT INTO `roadmaps` (`id`, `user_id`, `goal_title`, `data`, `created_at`) VALUES
(45, 4, 'ios developer Roadmap', '{\"goal_title\": \"ios developer Roadmap\", \"description\": \"Mastering advanced iOS development skills to create high-performance, scalable, and maintainable applications\", \"modules\": [{\"title\": \"Advanced Swift Fundamentals\", \"accent_color\": \"#6C63FF\", \"topics\": [{\"title\": \"Swift Concurrency\", \"duration\": \"2h\", \"description\": \"Learn how to write concurrent code using Swift\", \"key_concepts\": \"async/await, concurrency, parallelism\", \"id\": \"45_swift_concurrency\"}, {\"title\": \"Swift Generics\", \"duration\": \"1 day\", \"description\": \"Understand how to use generics to write reusable code\", \"key_concepts\": \"type parameters, generic functions, generic classes\", \"id\": \"45_swift_generics\"}, {\"title\": \"Swift Protocol-Oriented Programming\", \"duration\": \"1 day\", \"description\": \"Learn how to use protocols to define blueprints for objects\", \"key_concepts\": \"protocols, protocol extensions, protocol-oriented programming\", \"id\": \"45_swift_protocol-oriented_programming\"}]}, {\"title\": \"Core iOS Tools and Frameworks\", \"accent_color\": \"#EC4899\", \"topics\": [{\"title\": \"Xcode 14\", \"duration\": \"1 week\", \"description\": \"Get familiar with the latest Xcode features and tools\", \"key_concepts\": \"Xcode, Swift Package Manager, debugging\", \"id\": \"45_xcode_14\"}, {\"title\": \"SwiftUI\", \"duration\": \"3 days\", \"description\": \"Learn how to build user interfaces using SwiftUI\", \"key_concepts\": \"SwiftUI, views, modifiers, state, bindings\", \"id\": \"45_swiftui\"}, {\"title\": \"Core Data\", \"duration\": \"2 days\", \"description\": \"Understand how to manage data using Core Data\", \"key_concepts\": \"Core Data, data modeling, persistence\", \"id\": \"45_core_data\"}]}, {\"title\": \"Advanced iOS Frameworks\", \"accent_color\": \"#06B6D4\", \"topics\": [{\"title\": \"Combine Framework\", \"duration\": \"2 days\", \"description\": \"Learn how to use the Combine framework for reactive programming\", \"key_concepts\": \"Combine, publishers, subscribers, reactive programming\", \"id\": \"45_combine_framework\"}, {\"title\": \"Core Animation\", \"duration\": \"1 day\", \"description\": \"Understand how to create animations using Core Animation\", \"key_concepts\": \"Core Animation, layers, animations, transitions\", \"id\": \"45_core_animation\"}, {\"title\": \"ARKit\", \"duration\": \"2 days\", \"description\": \"Learn how to build augmented reality experiences using ARKit\", \"key_concepts\": \"ARKit, AR, augmented reality\", \"id\": \"45_arkit\"}]}, {\"title\": \"Data Structures and Algorithms\", \"accent_color\": \"#10B981\", \"topics\": [{\"title\": \"Arrays and Linked Lists\", \"duration\": \"1 day\", \"description\": \"Understand the basics of arrays and linked lists\", \"key_concepts\": \"arrays, linked lists, data structures\", \"id\": \"45_arrays_and_linked_lists\"}, {\"title\": \"Stacks and Queues\", \"duration\": \"1 day\", \"description\": \"Learn how to use stacks and queues to solve problems\", \"key_concepts\": \"stacks, queues, data structures\", \"id\": \"45_stacks_and_queues\"}, {\"title\": \"Trees and Graphs\", \"duration\": \"2 days\", \"description\": \"Understand how to work with trees and graphs\", \"key_concepts\": \"trees, graphs, data structures\", \"id\": \"45_trees_and_graphs\"}]}, {\"title\": \"System Design and Architecture\", \"accent_color\": \"#F59E0B\", \"topics\": [{\"title\": \"MVC and MVVM Patterns\", \"duration\": \"1 day\", \"description\": \"Learn how to apply MVC and MVVM patterns to iOS development\", \"key_concepts\": \"MVC, MVVM, architecture patterns\", \"id\": \"45_mvc_and_mvvm_patterns\"}, {\"title\": \"Clean Architecture\", \"duration\": \"2 days\", \"description\": \"Understand how to apply clean architecture principles to iOS development\", \"key_concepts\": \"clean architecture, separation of concerns, dependency injection\", \"id\": \"45_clean_architecture\"}, {\"title\": \"Microservices Architecture\", \"duration\": \"2 days\", \"description\": \"Learn how to design microservices-based systems\", \"key_concepts\": \"microservices, service-oriented architecture, scalability\", \"id\": \"45_microservices_architecture\"}]}, {\"title\": \"Databases and Storage\", \"accent_color\": \"#F97316\", \"topics\": [{\"title\": \"Core Data Storage\", \"duration\": \"1 day\", \"description\": \"Understand how to use Core Data for storage\", \"key_concepts\": \"Core Data, storage, persistence\", \"id\": \"45_core_data_storage\"}, {\"title\": \"Realm Database\", \"duration\": \"1 day\", \"description\": \"Learn how to use Realm for mobile database management\", \"key_concepts\": \"Realm, database, mobile storage\", \"id\": \"45_realm_database\"}, {\"title\": \"Firebase Realtime Database\", \"duration\": \"2 days\", \"description\": \"Understand how to use Firebase Realtime Database for cloud-based storage\", \"key_concepts\": \"Firebase, Realtime Database, cloud storage\", \"id\": \"45_firebase_realtime_database\"}]}, {\"title\": \"Cloud and Networking\", \"accent_color\": \"#8B5CF6\", \"topics\": [{\"title\": \"AWS Amplify\", \"duration\": \"2 days\", \"description\": \"Learn how to use AWS Amplify for cloud-based services\", \"key_concepts\": \"AWS Amplify, cloud services, authentication\", \"id\": \"45_aws_amplify\"}, {\"title\": \"Firebase Cloud Functions\", \"duration\": \"1 day\", \"description\": \"Understand how to use Firebase Cloud Functions for serverless computing\", \"key_concepts\": \"Firebase, Cloud Functions, serverless\", \"id\": \"45_firebase_cloud_functions\"}, {\"title\": \"HTTP and HTTPS Protocols\", \"duration\": \"1 day\", \"description\": \"Learn how to work with HTTP and HTTPS protocols\", \"key_concepts\": \"HTTP, HTTPS, networking\", \"id\": \"45_http_and_https_protocols\"}]}, {\"title\": \"Security and Testing\", \"accent_color\": \"#EF4444\", \"topics\": [{\"title\": \"iOS Security Best Practices\", \"duration\": \"1 day\", \"description\": \"Understand how to follow iOS security best practices\", \"key_concepts\": \"security, best practices, iOS\", \"id\": \"45_ios_security_best_practices\"}, {\"title\": \"Unit Testing and UI Testing\", \"duration\": \"2 days\", \"description\": \"Learn how to write unit tests and UI tests for iOS applications\", \"key_concepts\": \"unit testing, UI testing, testing frameworks\", \"id\": \"45_unit_testing_and_ui_testing\"}, {\"title\": \"Code Review and Refactoring\", \"duration\": \"1 day\", \"description\": \"Understand how to perform code reviews and refactor code\", \"key_concepts\": \"code review, refactoring, code quality\", \"id\": \"45_code_review_and_refactoring\"}]}, {\"title\": \"Production and Deployment\", \"accent_color\": \"#3B82F6\", \"topics\": [{\"title\": \"Xcode Build and Archive\", \"duration\": \"1 day\", \"description\": \"Learn how to build and archive iOS applications using Xcode\", \"key_concepts\": \"Xcode, build, archive\", \"id\": \"45_xcode_build_and_archive\"}, {\"title\": \"App Store Optimization\", \"duration\": \"1 day\", \"description\": \"Understand how to optimize iOS applications for the App Store\", \"key_concepts\": \"App Store, optimization, marketing\", \"id\": \"45_app_store_optimization\"}, {\"title\": \"Continuous Integration and Continuous Deployment\", \"duration\": \"2 days\", \"description\": \"Learn how to set up CI/CD pipelines for iOS development\", \"key_concepts\": \"CI/CD, pipelines, automation\", \"id\": \"45_continuous_integration_and_continuous_deployment\"}]}, {\"title\": \"Career Development and Networking\", \"accent_color\": \"#14B8A6\", \"topics\": [{\"title\": \"Resume Building and Interview Preparation\", \"duration\": \"1 day\", \"description\": \"Understand how to build a strong resume and prepare for iOS development interviews\", \"key_concepts\": \"resume, interview, career development\", \"id\": \"45_resume_building_and_interview_preparation\"}, {\"title\": \"Networking and Community Involvement\", \"duration\": \"1 day\", \"description\": \"Learn how to get involved in the iOS development community and network with other developers\", \"key_concepts\": \"networking, community, career development\", \"id\": \"45_networking_and_community_involvement\"}, {\"title\": \"Staying Up-to-Date with Industry Trends\", \"duration\": \"1 week\", \"description\": \"Understand how to stay current with the latest iOS development trends and technologies\", \"key_concepts\": \"industry trends, career development, continuous learning\", \"id\": \"45_staying_up-to-date_with_industry_trends\"}]}], \"source\": \"AI Generated\", \"is_saved\": true, \"id\": \"45\"}', '2026-04-02 07:51:53');
